customCss:
body {
    background-color: #000000;
    margin: 0;
    padding: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}
.card {
    background-color: #000000;
    color: #ffffff;
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    font-size: 22px;
    text-align: center;
    line-height: 1.6;
    border: 1px solid #ffffff;
    border-radius: 15px;
    padding: 30px;
    width: 80%;
    max-width: 600px;
    margin: auto;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.8), 0 0 20px rgba(255, 255, 255, 0.15);
}
.source-link {
    color: #a0a0a0;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    transition: color 0.35s, transform 0.35s;
}
.source-link:hover {
    color: #3b82f6;
    transform: scale(1.05);
}
b, strong {
    color: #FF005E;
    text-shadow: 0 0 8px rgba(255, 0, 94, 0.6), 0 0 15px rgba(255, 0, 94, 0.4);
}
i, em {
    color: #5EFF00;
    text-shadow: 0 0 8px rgba(94, 255, 0, 0.6), 0 0 15px rgba(94, 255, 0, 0.4);
}
b i, strong em, i b, em strong {
    color: #005EFF;
    text-shadow: 0 0 8px rgba(0, 94, 255, 0.6), 0 0 20px rgba(0, 94, 255, 0.5);
}
